import React, { useEffect, useState } from "react";
import { Container, Grid, Paper, Typography, Button, CircularProgress } from "@mui/material";
import { useAuth } from "../contexts/AuthContext";

export default function AdminDashboard() {
  const { auth } = useAuth();
  const [overview, setOverview] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchOverview = async () => {
      try {
        const res = await fetch("/api/admin/overview", {
          headers: { Authorization: `Bearer ${auth.token}` },
        });
        const data = await res.json();
        setOverview(data);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchOverview();
  }, [auth.token]);

  if (loading) return <CircularProgress />;

  return (
    <Container sx={{ mt: 4 }}>
      <Typography variant="h4" sx={{ mb: 3 }}>Admin Dashboard</Typography>
      <Grid container spacing={3}>
        {overview && Object.entries(overview).map(([key, value]) => (
          <Grid item xs={12} sm={6} md={3} key={key}>
            <Paper sx={{ p: 2, textAlign: "center" }}>
              <Typography variant="h6" sx={{ textTransform: "capitalize" }}>{key}</Typography>
              <Typography variant="h4">{value}</Typography>
            </Paper>
          </Grid>
        ))}
      </Grid>
    </Container>
  );
}
